import{_ as r,o as a,c as t,af as o}from"./chunks/framework.BSym9njW.js";const b=JSON.parse('{"title":"Torch-RecHub 推荐系统实战","description":"","frontmatter":{},"headers":[],"relativePath":"zh/05-amd-yes/torch-rechub/index.md","filePath":"zh/05-amd-yes/torch-rechub/index.md","lastUpdated":1778553795000}'),h={name:"zh/05-amd-yes/torch-rechub/index.md"};function l(c,e,i,s,n,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="torch-rechub-推荐系统实战" tabindex="-1">Torch-RecHub 推荐系统实战 <a class="header-anchor" href="#torch-rechub-推荐系统实战" aria-label="Permalink to &quot;Torch-RecHub 推荐系统实战&quot;">​</a></h1><p align="center"><a href="https://pypi.org/project/torch-rechub/"><img alt="PyPI" src="https://img.shields.io/pypi/v/torch-rechub?style=for-the-badge&amp;color=005A9C&amp;label=torch-rechub"></a><a href="https://www.python.org/"><img alt="Python" src="https://img.shields.io/badge/python-3.9%2B-012A4A?style=for-the-badge"></a><a href="https://pytorch.org/"><img alt="PyTorch" src="https://img.shields.io/badge/pytorch-1.10%2B-EE4C2C?style=for-the-badge"></a><a href="https://rocm.docs.amd.com/"><img alt="ROCm" src="https://img.shields.io/badge/AMD%20ROCm-ready-ED1C24?style=for-the-badge"></a><a href="https://github.com/datawhalechina/torch-rechub"><img alt="GitHub stars" src="https://img.shields.io/github/stars/datawhalechina/torch-rechub?style=for-the-badge&amp;color=00C8FF"></a></p><p>本目录收录 <a href="https://github.com/datawhalechina/torch-rechub" target="_blank" rel="noreferrer">Torch-RecHub</a> 在 AMD GPU / ROCm 环境下的推荐系统实战教程。目标不只是跑通几个模型，而是理解一个现代推荐系统训练链路如何组织：特征定义、数据生成器、训练器、排序与召回模型、实验跟踪，以及面向服务部署的模型导出。</p><p>Torch-RecHub 是一个轻量、高效、易用的 PyTorch 推荐系统框架，面向工业级推荐实验的快速复现与扩展。项目提供 30+ 主流推荐模型，覆盖精排、召回、多任务学习和生成式推荐，并提供统一的数据加载、训练评估、实验跟踪和 ONNX 导出能力。</p><h2 id="为什么放在-hello-rocm" tabindex="-1">为什么放在 hello-rocm <a class="header-anchor" href="#为什么放在-hello-rocm" aria-label="Permalink to &quot;为什么放在 hello-rocm&quot;">​</a></h2><p>在 hello-rocm 中，这组案例聚焦 <strong>AMD GPU / ROCm 上的推荐系统实践</strong>。你会学习如何安装 ROCm 适配的 PyTorch，如何在 AMD 硬件上运行 Torch-RecHub 教程，并把训练流程进一步连接到 ONNX 导出、轻量召回验证等部署相关环节。</p><p>这些教程使用轻量样例数据，适合在本地快速验证完整流程。文中的指标主要用于确认链路跑通，不代表生产数据集上的最终效果。</p><h2 id="你会学到什么" tabindex="-1">你会学到什么 <a class="header-anchor" href="#你会学到什么" aria-label="Permalink to &quot;你会学到什么&quot;">​</a></h2><ul><li>DeepFM 如何把 dense / sparse 特征用于 CTR 预估。</li><li>DIN 如何用候选物品对用户历史行为序列做 attention。</li><li>DSSM 如何构建双塔召回模型，并使用 item embedding 做检索。</li><li>MMOE 如何在多个推荐目标之间共享 expert 并分配任务 tower。</li><li>Torch-RecHub 如何通过统一的 <code>model_logger</code> 接入 WandB、SwanLab、TensorBoardX。</li><li>排序与召回模型如何导出 ONNX，并用 ONNXRuntime 做最小推理验证。</li></ul><h2 id="torch-rechub-项目特色" tabindex="-1">Torch-RecHub 项目特色 <a class="header-anchor" href="#torch-rechub-项目特色" aria-label="Permalink to &quot;Torch-RecHub 项目特色&quot;">​</a></h2><ul><li><strong>PyTorch 优先</strong>：基于 PyTorch 动态图和硬件加速能力，支持 CPU、NVIDIA CUDA GPU、AMD ROCm GPU 和华为昇腾 NPU。</li><li><strong>模型库丰富</strong>：内置 30+ 推荐模型，覆盖 ranking、matching、multi-task learning 和 generative recommendation。</li><li><strong>模块化设计</strong>：特征、层、训练器、损失、指标和工具相互解耦，方便扩展新模型和新数据集。</li><li><strong>标准化流程</strong>：提供统一的数据加载、训练、评估、实验跟踪和模型导出路径。</li><li><strong>部署友好</strong>：支持 ONNX 导出和推理验证，帮助从训练走向服务化。</li><li><strong>实验跟踪</strong>：统一接入 WandB、SwanLab、TensorBoardX，便于记录超参和指标。</li></ul><h2 id="教程目录" tabindex="-1">教程目录 <a class="header-anchor" href="#教程目录" aria-label="Permalink to &quot;教程目录&quot;">​</a></h2><ol><li><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/00_QuickStart_CTR_DeepFM">CTR 预测：DeepFM</a></li><li><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/01_Ranking_DIN">序列兴趣建模：DIN</a></li><li><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/02_Matching_DSSM">匹配/召回：DSSM</a></li><li><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/03_MultiTask_MMOE">多任务学习：MMOE</a></li><li><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/04_Experiment_Tracking_Light">实验跟踪：model_logger 接入</a></li><li><a href="/hello-rocm/zh/05-amd-yes/torch-rechub/05_Model_Export_and_Serving">模型导出与推理验证：ONNX</a></li></ol>',13)])])}const g=r(h,[["render",l]]);export{b as __pageData,g as default};
